  1→"use client";
  2→
  3→import { memo, useMemo, useState, useRef, useEffect, useCallback } from "react";
  4→import { Handle, Position, NodeResizer, type NodeProps } from "@xyflow/react";
  5→import { Minus, Plus } from "lucide-react";
  6→import { ConnectHandle } from "./ConnectHandle";
  7→import { useFlowStore } from "@/store/useFlowStore";
  8→import { computeColor } from "@/lib/color";
  9→import { calculateMinComponentSize } from "@/lib/component-children";
 10→import { strokeDasharray } from "./svgBorderUtils";
 11→import type { FlowNode } from "@/store/types";
 12→
 13→/** Fixed offset (px) for the vertical lines in collapsed predefined-process shape */
 14→const COLLAPSED_LINE_OFFSET = 12;
 15→
 16→export const ComponentInstanceNode = memo(function ComponentInstanceNode({ id, data, selected, width, height }: NodeProps<FlowNode>) {
 17→  const collapsed = data.collapsed ?? false;
 18→  const toggleComponentCollapse = useFlowStore((s) => s.toggleComponentCollapse);
 19→  const updateComponentInstanceName = useFlowStore((s) => s.updateComponentInstanceName);
 20→  const direction = data.componentDefinitionDirection ?? useFlowStore((s) => s.direction);
 21→  const componentDef = useFlowStore((s) => {
 22→    const defId = data.componentDefinitionId;
 23→    return defId ? s.componentDefinitions.find((d) => d.id === defId) : undefined;
 24→  });
 25→  const minSize = useMemo(
 26→    () => componentDef ? calculateMinComponentSize(componentDef) : { minWidth: 180, minHeight: 80 },
 27→    [componentDef],
 28→  );
 29→
 30→  const [editingName, setEditingName] = useState(false);
 31→  const [nameValue, setNameValue] = useState(data.componentInstanceName ?? "");
 32→  const nameInputRef = useRef<HTMLInputElement>(null);
 33→  const [hovered, setHovered] = useState(false);
 34→  const handleVisible = hovered || !!selected;
 35→
 36→  // Compute style colors
 37→  const computedFill = computeColor(data.fillColor, data.fillOpacity, data.fillLightness);
 38→  const computedBorder = computeColor(data.borderColor, data.borderOpacity, data.borderLightness);
 39→  const computedText = computeColor(data.textColor, data.textOpacity, data.textLightness);
 40→  const borderWidth = data.borderWidth ?? 2;
 41→  const borderStyle = data.borderStyle ?? "solid";
 42→  const fontSize = data.fontSize ?? 14;
 43→  const textStyle: React.CSSProperties = {
 44→    color: computedText ?? "var(--foreground)",
 45→    fontWeight: data.bold ? "bold" : undefined,
 46→    fontStyle: data.italic ? "italic" : undefined,
 47→    textDecoration: data.underline ? "underline" : undefined,
 48→  };
 49→
 50→  // Direction-aware: TD → top=target, bottom=source; LR → left=target, right=source
 51→  const entryPos = direction === "LR" ? Position.Left : Position.Top;
 52→  const exitPos = direction === "LR" ? Position.Right : Position.Bottom;
 53→
 54→  useEffect(() => {
 55→    setNameValue(data.componentInstanceName ?? "");
 56→  }, [data.componentInstanceName]);
 57→
 58→  useEffect(() => {
 59→    if (editingName && nameInputRef.current) {
 60→      nameInputRef.current.focus();
 61→      nameInputRef.current.select();
 62→    }
 63→  }, [editingName]);
 64→
 65→  const commitName = useCallback(() => {
 66→    setEditingName(false);
 67→    const trimmed = nameValue.trim();
 68→    if (trimmed && trimmed !== (data.componentInstanceName ?? "")) {
 69→      updateComponentInstanceName(id, trimmed);
 70→    } else {
 71→      setNameValue(data.componentInstanceName ?? "");
 72→    }
 73→  }, [nameValue, data.componentInstanceName, id, updateComponentInstanceName]);
 74→
 75→  // Hidden handles for bridge edge internal connections (entry-incoming + exit-outgoing only)
 76→  const bridgeHandles = (
 77→    <>
 78→      <Handle
 79→        type="source"
 80→        position={entryPos}
 81→        id="bridge-entry-source"
 82→        isConnectable={false}
 83→        style={{ width: 0, height: 0, opacity: 0, pointerEvents: "none" }}
 84→      />
 85→      <Handle
 86→        type="target"
 87→        position={exitPos}
 88→        id="bridge-exit-target"
 89→        isConnectable={false}
 90→        style={{ width: 0, height: 0, opacity: 0, pointerEvents: "none" }}
 91→      />
 92→    </>
 93→  );
 94→
 95→  // Collapsed view — predefined process shape (rectangle with vertical lines on sides)
 96→  if (collapsed) {
 97→    return (
 98→      <div
 99→        className="relative w-full h-full"
100→        onMouseEnter={() => setHovered(true)}
101→        onMouseLeave={() => setHovered(false)}
102→      >
103→        <NodeResizer
104→          isVisible={!!selected}
105→          minWidth={60}
106→          minHeight={30}
107→          lineClassName="!border-primary"
108→          handleClassName="!w-2 !h-2 !bg-primary !border-primary"
109→        />
110→        <svg
111→          className="absolute inset-0 w-full h-full"
112→          viewBox={`0 0 ${width ?? 150} ${height ?? 50}`}
113→        >
114→          <rect
115→            x="0" y="0" width={width ?? 150} height={height ?? 50}
116→            fill={computedFill ?? "var(--muted)"}
117→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
118→            strokeWidth={borderWidth}
119→            vectorEffect="non-scaling-stroke"
120→            strokeDasharray={strokeDasharray(borderStyle)}
121→          />
122→          <line
123→            x1={COLLAPSED_LINE_OFFSET} y1="0" x2={COLLAPSED_LINE_OFFSET} y2={height ?? 50}
124→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
125→            strokeWidth={borderWidth}
126→            vectorEffect="non-scaling-stroke"
127→            strokeDasharray={strokeDasharray(borderStyle)}
128→          />
129→          <line
130→            x1={(width ?? 150) - COLLAPSED_LINE_OFFSET} y1="0" x2={(width ?? 150) - COLLAPSED_LINE_OFFSET} y2={height ?? 50}
131→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
132→            strokeWidth={borderWidth}
133→            vectorEffect="non-scaling-stroke"
134→            strokeDasharray={strokeDasharray(borderStyle)}
135→          />
136→        </svg>
137→        <div className="relative flex items-center w-full h-full px-5" style={textStyle}>
138→          {editingName ? (
139→            <input
140→              ref={nameInputRef}
141→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0 text-center"
142→              style={{ color: "inherit", fontSize }}
143→              value={nameValue}
144→              onChange={(e) => setNameValue(e.target.value)}
145→              onBlur={commitName}
146→              onKeyDown={(e) => {
147→                if (e.key === "Enter") commitName();
148→                if (e.key === "Escape") { setNameValue(data.componentInstanceName ?? ""); setEditingName(false); }
149→              }}
150→            />
151→          ) : (
152→            <span
153→              className="flex-1 font-medium truncate text-center cursor-default"
154→              style={{ fontSize }}
155→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
156→            >
157→              {data.componentInstanceName ?? data.label}
158→            </span>
159→          )}
160→          <button
161→            className="nodrag shrink-0 flex items-center justify-center w-5 h-5 rounded border cursor-pointer"
162→            style={{ background: "var(--background)", borderColor: "color-mix(in srgb, var(--foreground) 50%, transparent)" }}
163→            onClick={() => toggleComponentCollapse(id)}
164→            title="Expand"
165→          >
166→            <Plus size={12} />
167→          </button>
168→        </div>
169→        <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
170→        <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
171→        <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
172→        <ConnectHandle pos={exitPos} type="source" visible={handleVisible} nodeId={id} />
173→        {bridgeHandles}
174→      </div>
175→    );
176→  }
177→
178→  // Expanded view - just a container with header; child nodes are rendered by React Flow
179→  return (
180→    <div
181→      className="w-full h-full"
182→      onMouseEnter={() => setHovered(true)}
183→      onMouseLeave={() => setHovered(false)}
184→    >
185→      <NodeResizer
186→        isVisible={!!selected}
187→        minWidth={minSize.minWidth}
188→        minHeight={minSize.minHeight}
189→        lineClassName="!border-primary"
190→        handleClassName="!w-2 !h-2 !bg-primary !border-primary"
191→      />
192→      <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
193→      <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
194→      <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
195→      <ConnectHandle pos={exitPos} type="source" visible={handleVisible} nodeId={id} />
196→      {bridgeHandles}
197→      <div
198→        className="w-full h-full rounded-md overflow-hidden flex flex-col"
199→        style={{
200→          border: `${borderWidth}px ${borderStyle} ${computedBorder ?? "var(--color-muted-foreground)"}`,
201→        }}
202→      >
203→        {/* Header */}
204→        <div
205→          className="flex items-center gap-2 px-3 py-1.5 shrink-0"
206→          style={{ background: computedFill ?? "var(--muted)", ...textStyle }}
207→        >
208→          {editingName ? (
209→            <input
210→              ref={nameInputRef}
211→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0"
212→              style={{ color: "inherit", fontSize }}
213→              value={nameValue}
214→              onChange={(e) => setNameValue(e.target.value)}
215→              onBlur={commitName}
216→              onKeyDown={(e) => {
217→                if (e.key === "Enter") commitName();
218→                if (e.key === "Escape") { setNameValue(data.componentInstanceName ?? ""); setEditingName(false); }
219→              }}
220→            />
221→          ) : (
222→            <span
223→              className="font-semibold truncate flex-1 cursor-default"
224→              style={{ fontSize }}
225→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
226→            >
227→              {data.componentInstanceName ?? data.label}
228→            </span>
229→          )}
230→          <button
231→            className="nodrag shrink-0 flex items-center justify-center w-5 h-5 rounded border cursor-pointer"
232→            style={{ background: "var(--background)", borderColor: "color-mix(in srgb, var(--foreground) 50%, transparent)" }}
233→            onClick={() => toggleComponentCollapse(id)}
234→            title="Collapse"
235→          >
236→            <Minus size={12} />
237→          </button>
238→        </div>
239→
240→        {/* Body area - child nodes are rendered by React Flow as real nodes */}
241→        <div className="flex-1" style={{ background: "var(--background)" }} />
242→      </div>
243→    </div>
244→  );
245→});
246→

