 38→export function generateComponentChildren(opts: GenerateChildrenOptions): GenerateChildrenResult {
 39→  const { parentId, def, hidden = false, direction } = opts;
 40→  const effectiveDirection = direction ?? def.direction ?? "TD";
 41→
 42→  // Exclude entry/exit nodes
 43→  const excludeIds = new Set<string>();
 44→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
 45→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
 46→
 47→  // Find min position to normalize origin
 48→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
 49→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
 50→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
 51→
 52→  const childNodes: FlowNode[] = visibleNodes
 53→    .map((n) => {
 54→      const origW = n.style?.width ?? CHILD_NODE_W;
 55→      const origH = n.style?.height ?? CHILD_NODE_H;
 56→      const scaledFontSize = Math.round((n.fontSize ?? 14) * CHILD_SCALE);
 57→      return {
 58→        id: `${parentId}_${n.id}`,
 59→        type: n.shape,
 60→        position: {
 61→          x: (n.position.x - minX) * CHILD_SCALE + COMPONENT_PADDING,
 62→          y: (n.position.y - minY) * CHILD_SCALE + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING,
 63→        },
 64→        parentId,
 65→        selectable: false,
 66→        draggable: false,
 67→        data: {
 68→          label: n.label,
 69→          shape: n.shape as NodeShape,
 70→          componentParentId: parentId,
 71→          componentInternalId: n.id,
 72→          ...(n.fillColor ? { fillColor: n.fillColor } : {}),
 73→          ...(n.fillOpacity !== undefined ? { fillOpacity: n.fillOpacity } : {}),
 74→          ...(n.fillLightness !== undefined ? { fillLightness: n.fillLightness } : {}),
 75→          ...(n.borderColor ? { borderColor: n.borderColor } : {}),
 76→          ...(n.borderOpacity !== undefined ? { borderOpacity: n.borderOpacity } : {}),
 77→          ...(n.borderLightness !== undefined ? { borderLightness: n.borderLightness } : {}),
 78→          ...(n.borderWidth ? { borderWidth: n.borderWidth } : {}),
 79→          ...(n.borderStyle ? { borderStyle: n.borderStyle } : {}),
 80→          fontSize: scaledFontSize,
 81→          ...(n.textColor ? { textColor: n.textColor } : {}),
 82→          ...(n.textOpacity !== undefined ? { textOpacity: n.textOpacity } : {}),
 83→          ...(n.textLightness !== undefined ? { textLightness: n.textLightness } : {}),
 84→          ...(n.textAlign ? { textAlign: n.textAlign } : {}),
 85→          ...(n.textVerticalAlign ? { textVerticalAlign: n.textVerticalAlign } : {}),
 86→          ...(n.bold ? { bold: n.bold } : {}),
 87→          ...(n.italic ? { italic: n.italic } : {}),
 88→          ...(n.underline ? { underline: n.underline } : {}),
 89→        },
 90→        style: {
 91→          width: Math.round(origW * CHILD_SCALE),
 92→          height: Math.round(origH * CHILD_SCALE),
 93→        },
 94→        hidden,
 95→      };
 96→    });
