132→export function calculateComponentSize(def: ComponentDefinition): { width: number; height: number } {
133→  // Exclude entry/exit nodes from size calculation
134→  const excludeIds = new Set<string>();
135→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
136→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
137→
138→  const sizeNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
139→  const sMinX = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.x)) : 0;
140→  const sMinY = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.y)) : 0;
141→
142→  let maxX = 0;
143→  let maxY = 0;
144→  for (const n of sizeNodes) {
145→    const right = (n.position.x - sMinX + (n.style?.width ?? CHILD_NODE_W)) * CHILD_SCALE;
146→    const bottom = (n.position.y - sMinY + (n.style?.height ?? CHILD_NODE_H)) * CHILD_SCALE;
147→    if (right > maxX) maxX = right;
148→    if (bottom > maxY) maxY = bottom;
149→  }
150→  return {
151→    width: Math.max(200, Math.round(maxX) + COMPONENT_PADDING * 2),
152→    height: Math.max(120, Math.round(maxY) + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING * 2),
153→  };
154→}
