156→/**
157→ * Recompute child node positions from the definition's base layout,
158→ * scaled to fit the current parent content area. Child node sizes are kept fixed.
159→ */
160→export function rescaleComponentChildren(
161→  childNodes: FlowNode[],
162→  parentId: string,
163→  def: ComponentDefinition,
164→  parentW: number,
165→  parentH: number,
166→): FlowNode[] {
167→  const baseSize = calculateComponentSize(def);
168→  const baseContentW = baseSize.width - COMPONENT_PADDING * 2;
169→  const baseContentH = baseSize.height - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
170→  const currentContentW = parentW - COMPONENT_PADDING * 2;
171→  const currentContentH = parentH - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
172→  if (baseContentW <= 0 || baseContentH <= 0 || currentContentW <= 0 || currentContentH <= 0) return childNodes;
173→
174→  const scale = Math.min(currentContentW / baseContentW, currentContentH / baseContentH);
175→
176→  // Exclude entry/exit nodes from the definition (same logic as generateComponentChildren)
177→  const excludeIds = new Set<string>();
178→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
179→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
180→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
181→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
182→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
183→
184→  // Build a map from definition node id → base position
185→  const baseMap = new Map<string, { x: number; y: number }>();
186→  for (const n of visibleNodes) {
187→    baseMap.set(n.id, {
188→      x: (n.position.x - minX) * CHILD_SCALE,
189→      y: (n.position.y - minY) * CHILD_SCALE,
190→    });
191→  }
192→
193→  return childNodes.map((child) => {
194→    if (child.data.componentParentId !== parentId) return child;
195→    const internalId = child.data.componentInternalId as string | undefined;
196→    if (!internalId) return child;
197→    const base = baseMap.get(internalId);
198→    if (!base) return child;
199→
200→    return {
201→      ...child,
202→      position: {
203→        x: COMPONENT_PADDING + base.x * scale,
204→        y: COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING + base.y * scale,
205→      },
206→      // Child node sizes are NOT scaled — keep original size from definition
207→    };
208→  });
209→}
