211→/**
212→ * Calculate minimum parent size that prevents child nodes from overflowing.
213→ * Used as minWidth/minHeight for NodeResizer.
214→ */
215→export function calculateMinComponentSize(def: ComponentDefinition): { minWidth: number; minHeight: number } {
216→  const excludeIds = new Set<string>();
217→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
218→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
219→
220→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
221→  if (visibleNodes.length === 0) return { minWidth: 180, minHeight: 80 };
222→
223→  // Find the maximum right/bottom extent of child nodes at scale=1 (base CHILD_SCALE)
224→  const minX = Math.min(...visibleNodes.map((n) => n.position.x));
225→  const minY = Math.min(...visibleNodes.map((n) => n.position.y));
226→
227→  let maxRight = 0;
228→  let maxBottom = 0;
229→  for (const n of visibleNodes) {
230→    const w = (n.style?.width ?? CHILD_NODE_W) * CHILD_SCALE;
231→    const h = (n.style?.height ?? CHILD_NODE_H) * CHILD_SCALE;
232→    const right = (n.position.x - minX) * CHILD_SCALE + w;
233→    const bottom = (n.position.y - minY) * CHILD_SCALE + h;
234→    if (right > maxRight) maxRight = right;
235→    if (bottom > maxBottom) maxBottom = bottom;
236→  }
237→
238→  return {
239→    minWidth: Math.max(180, Math.round(maxRight) + COMPONENT_PADDING * 2),
240→    minHeight: Math.max(80, Math.round(maxBottom) + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING * 2),
241→  };
242→}
