288→export function generateBridgeEdges(opts: {
289→  parentId: string;
290→  def: ComponentDefinition;
291→  allEdges: FlowEdge[];
292→  direction?: "TD" | "LR";
293→}): FlowEdge[] {
294→  const { parentId, def, allEdges, direction = "TD" } = opts;
