  3→import { useCallback, useRef, useEffect } from "react";
  4→import { useStoreApi } from "@xyflow/react";
  5→import { getNodesInside } from "@xyflow/system";
  6→import { perfStart, perfEnd, perfCount } from "@/lib/perf";
  7→import type {
  8→  Node,
  9→  Edge,
 10→  NodeMouseHandler,
 11→  EdgeMouseHandler,
 12→  NodeChange,
 13→  EdgeChange,
 14→} from "@xyflow/react";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→type EdgeInfo = { id: string; source: string; target: string; data?: { isBridgeEdge?: boolean } };
 21→
 22→export interface UseCtrlSelectionOptions {
 23→  /** Read current selected IDs */
 24→  getSelectedIds: () => Set<string>;
 25→  /** Apply new selected IDs */
 26→  setSelectedIds: (ids: Set<string>) => void;
 27→
 28→  /** Provide edges — used for drag‐selection "both‐endpoints" rule and Ctrl+A */
 29→  getEdges?: () => readonly EdgeInfo[];
 30→
 31→  /** Return all selectable IDs for Ctrl+A. Omit to skip Ctrl+A handling. */
 32→  getAllSelectableIds?: () => Set<string>;
 33→
 34→  /** Currently highlighted ID (BulkEdit: include in starting set on Ctrl+click) */
 35→  highlightId?: string | null;
 36→
 37→  /** Called on normal (non-Ctrl) node click. If omitted, ReactFlow default applies. */
 38→  onNormalNodeClick?: (nodeId: string) => void;
 39→  /** Called on normal (non-Ctrl) edge click. If omitted, ReactFlow default applies. */
 40→  onNormalEdgeClick?: (edgeId: string) => void;
 41→  /** Called on pane click. If omitted, ReactFlow default applies. */
 42→  onNormalPaneClick?: () => void;
 43→}
 44→
 45→// ---------------------------------------------------------------------------
 46→// Helpers (module-level, no allocation per render)
 47→// ---------------------------------------------------------------------------
 48→
 49→/** Select edges whose BOTH source and target are in `ids`; deselect the rest. */
 50→function syncEdgeSelection(ids: Set<string>, edges: readonly EdgeInfo[]) {
 51→  for (const e of edges) {
 52→    if (e.data?.isBridgeEdge) continue;
 53→    if (ids.has(e.source) && ids.has(e.target)) ids.add(e.id);
 54→    else ids.delete(e.id);
 55→  }
 56→}
 57→
 58→/** Returns true if two Sets contain the same elements. */
 59→function setsEqual(a: Set<string>, b: Set<string>): boolean {
 60→  if (a.size !== b.size) return false;
 61→  for (const id of a) {
 62→    if (!b.has(id)) return false;
 63→  }
 64→  return true;
 65→}
 66→
 67→/** Build a Set of edge IDs for filtering node IDs from a mixed set. */
 68→function buildEdgeIdSet(edges: readonly { id: string }[]): Set<string> {
 69→  const s = new Set<string>();
 70→  for (const e of edges) s.add(e.id);
 71→  return s;
 72→}
 73→
 74→/** Extract only node IDs from a mixed selection set. */
 75→function extractNodeIds(ids: Set<string>, edgeIdSet: Set<string>): Set<string> {
 76→  const result = new Set<string>();
 77→  for (const id of ids) {
 78→    if (!edgeIdSet.has(id)) result.add(id);
 79→  }
 80→  return result;
 81→}
 82→
 83→/** Symmetric difference (XOR) of two sets. */
 84→function symmetricDifference(a: Set<string>, b: Set<string>): Set<string> {
 85→  const result = new Set<string>();
 86→  for (const id of a) { if (!b.has(id)) result.add(id); }
 87→  for (const id of b) { if (!a.has(id)) result.add(id); }
 88→  return result;
 89→}
 90→
 91→/** Apply `setSelectedIds` only when the selection actually changed. */
 92→function applyIfChanged(
 93→  next: Set<string>,
 94→  getSelectedIds: () => Set<string>,
 95→  setSelectedIds: (ids: Set<string>) => void,
 96→) {
 97→  if (!setsEqual(next, getSelectedIds())) {
 98→    setSelectedIds(next);
 99→  }
100→}
101→
102→/**
103→ * Sync React Flow's internal nodeLookup/edgeLookup to match our selection state.
104→ *
105→ * React Flow's `getSelectionChanges(items, ids, mutateItem=true)` directly mutates
106→ * `internalNode.selected` in nodeLookup. When we block those changes (e.g. blocking
107→ * resetSelectedElements during Ctrl+drag), the internal state diverges from our props.
108→ *
109→ * On re-render, `adoptUserNodes` with `checkEquality: true` reuses internal nodes
110→ * when the userNode reference hasn't changed — preserving the stale `.selected` value.
111→ * This function repairs that divergence by directly setting `.selected` to match our state.
112→ */
113→function syncInternalSelection(
114→  ids: Set<string>,
115→  rfStore: { getState: () => { nodeLookup: Map<string, { id: string; selected?: boolean }>; edgeLookup: Map<string, { id: string; selected?: boolean }> } },
116→) {
117→  const { nodeLookup, edgeLookup } = rfStore.getState();
118→  for (const [id, node] of nodeLookup) {
119→    node.selected = ids.has(id);
120→  }
121→  for (const [id, edge] of edgeLookup) {
122→    edge.selected = ids.has(id);
123→  }
124→}
125→
126→// ---------------------------------------------------------------------------
127→// Hook
128→// ---------------------------------------------------------------------------
129→
130→export function useCtrlSelection(options: UseCtrlSelectionOptions) {
131→  const optsRef = useRef(options);
132→  optsRef.current = options;
133→  const rfStore = useStoreApi();
134→
135→  // ---- Refs ----
136→  const isMultiSelectKeyHeld = useRef(false);
137→  const isDragging = useRef(false);
138→  const dragStartIds = useRef<Set<string>>(new Set());
139→  const highlightIdRef = useRef(options.highlightId);
140→  highlightIdRef.current = options.highlightId;
141→
142→  // ---- Ctrl/Meta key tracking + Ctrl+A ----
143→
144→  useEffect(() => {
145→    const onKeyDown = (e: KeyboardEvent) => {
146→      if (e.key === "Control" || e.key === "Meta") {
147→        isMultiSelectKeyHeld.current = true;
148→      }
149→      if ((e.ctrlKey || e.metaKey) && e.key === "a") {
150→        const tag = (e.target as HTMLElement)?.tagName;
151→        if (tag === "INPUT" || tag === "TEXTAREA") return;
152→        const o = optsRef.current;
153→        if (!o.getAllSelectableIds) return;
154→        e.preventDefault();
155→        o.setSelectedIds(o.getAllSelectableIds());
156→      }
157→    };
158→    const onKeyUp = (e: KeyboardEvent) => {
159→      if (e.key === "Control" || e.key === "Meta") {
160→        isMultiSelectKeyHeld.current = false;
161→      }
162→    };
163→    window.addEventListener("keydown", onKeyDown);
164→    window.addEventListener("keyup", onKeyUp);
165→    return () => {
166→      window.removeEventListener("keydown", onKeyDown);
167→      window.removeEventListener("keyup", onKeyUp);
168→    };
169→  }, []);
170→
171→  // ---- Selection drag lifecycle ----
172→
173→  const ctrlDragUnsubRef = useRef<(() => void) | null>(null);
174→
175→  /** Compute and apply XOR selection from current userSelectionRect. */
176→  const computeCtrlDragSelection = useCallback(() => {
177→    const o = optsRef.current;
178→    const edges = o.getEdges?.() ?? [];
179→    const { nodeLookup, transform, userSelectionRect } = rfStore.getState();
180→    const nodeBox = new Set<string>();
181→    if (userSelectionRect) {
182→      const nodesInBox = getNodesInside(nodeLookup, userSelectionRect, transform, true, true);
183→      for (const node of nodesInBox) nodeBox.add(node.id);
184→    }
185→    const edgeIdSet = buildEdgeIdSet(edges);
186→    const dragStartNodes = extractNodeIds(dragStartIds.current, edgeIdSet);
187→    const xorNodes = symmetricDifference(dragStartNodes, nodeBox);
188→    const next = new Set(xorNodes);
189→    syncEdgeSelection(next, edges);
190→    applyIfChanged(next, o.getSelectedIds, o.setSelectedIds);
191→    syncInternalSelection(next, rfStore);
192→  }, []);
193→
194→  const handleSelectionStart = useCallback(() => {
195→    isDragging.current = true;
196→    const o = optsRef.current;
197→    const start = new Set(o.getSelectedIds());
198→    if (start.size === 0 && highlightIdRef.current) {
199→      start.add(highlightIdRef.current);
200→    }
201→    dragStartIds.current = start;
202→
203→    // When Ctrl is held, subscribe to userSelectionRect changes to compute
204→    // XOR selection independently of React Flow's areSetsEqual optimization.
205→    if (isMultiSelectKeyHeld.current) {
206→      ctrlDragUnsubRef.current?.();
207→      ctrlDragUnsubRef.current = rfStore.subscribe(
208→        (state) => {
209→          if (!isDragging.current || !isMultiSelectKeyHeld.current) return;
210→          if (state.userSelectionRect) {
211→            computeCtrlDragSelection();
212→          }
213→        },
214→      );
215→    }
216→  }, [computeCtrlDragSelection]);
217→
218→  const handleSelectionEnd = useCallback(() => {
219→    isDragging.current = false;
220→    ctrlDragUnsubRef.current?.();
221→    ctrlDragUnsubRef.current = null;
222→  }, []);
223→
224→  // ---- processNodesChanges ----
225→  // Intercepts select-type changes, applies custom logic, returns the rest.
226→
227→  const processNodesChanges = useCallback(
228→    <N extends Node = Node>(changes: NodeChange<N>[]): NodeChange<N>[] => {
229→      const t = perfStart("processNodesChanges");
230→      perfCount("processNodesChanges");
231→      // Fast path: no select changes → passthrough
232→      let hasSelect = false;
233→      for (const c of changes) { if (c.type === "select") { hasSelect = true; break; } }
234→      if (!hasSelect) { perfEnd("processNodesChanges", t); return changes; }
235→
236→      const selects: NodeChange<N>[] = [];
237→      const rest: NodeChange<N>[] = [];
238→      for (const c of changes) {
239→        if (c.type === "select") selects.push(c);
240→        else rest.push(c);
241→      }
242→
243→      const o = optsRef.current;
244→      const edges = o.getEdges?.() ?? [];
245→
246→      if (isMultiSelectKeyHeld.current && isDragging.current) {
247→        // ── CTRL+DRAG (XOR) ──
248→        // Compute box contents directly using getNodesInside + userSelectionRect.
249→        // This bypasses React Flow Pane's areSetsEqual optimization that can skip
250→        // getSelectionChanges (and thus processNodesChanges) when the box contents
251→        // match the previous drag's final state.
252→        const { nodeLookup, transform, userSelectionRect } = rfStore.getState();
253→        const nodeBox = new Set<string>();
254→        if (userSelectionRect) {
255→          const nodesInBox = getNodesInside(nodeLookup, userSelectionRect, transform, true, true);
256→          for (const node of nodesInBox) nodeBox.add(node.id);
257→        }
258→
259→        // XOR with drag-start node IDs
260→        const edgeIdSet = buildEdgeIdSet(edges);
261→        const dragStartNodes = extractNodeIds(dragStartIds.current, edgeIdSet);
262→        const xorNodes = symmetricDifference(dragStartNodes, nodeBox);
263→
264→        // Add edges whose both endpoints are in the result
265→        const next = new Set(xorNodes);
266→        syncEdgeSelection(next, edges);
267→        applyIfChanged(next, o.getSelectedIds, o.setSelectedIds);
268→        syncInternalSelection(next, rfStore);
269→
270→      } else if (isMultiSelectKeyHeld.current) {
271→        // ── CTRL held, NOT dragging ──
272→        // Two possible sources:
273→        //   a) resetSelectedElements() preparing for a drag → userSelectionRect is set → BLOCK
274→        //   b) addSelectedNodes/unselectNodesAndEdges from Ctrl+click → no rect → ALLOW
275→        const { userSelectionRect } = rfStore.getState();
276→        if (userSelectionRect) {
277→          // BLOCK — resetSelectedElements before drag start.
278→          // Do NOT repair nodeLookup here: getSelectionChanges for the drag box
279→          // needs to see the reset state to correctly detect all changes.
280→          // nodeLookup will be repaired by syncInternalSelection in CTRL+DRAG branch.
281→        } else {
282→          // Ctrl+click — process changes normally with highlightId inclusion
283→          const next = new Set(o.getSelectedIds());
284→          if (next.size === 0 && highlightIdRef.current) {
285→            next.add(highlightIdRef.current);
286→          }
287→          for (const c of selects) {
288→            if (c.type === "select") {
289→              if (c.selected) next.add(c.id); else next.delete(c.id);
290→            }
291→          }
292→          applyIfChanged(next, o.getSelectedIds, o.setSelectedIds);
293→          syncInternalSelection(next, rfStore);
294→        }
295→
296→      } else {
297→        // ── NORMAL ──
