 3→/**
 4→ * Track whether the Shift key is currently pressed.
 5→ * Shared across components via a module-level listener (only one pair of
 6→ * keydown/keyup listeners is registered regardless of how many components
 7→ * call this hook).
 8→ */
 9→
10→let pressed = false;
11→const listeners = new Set<(v: boolean) => void>();
12→
13→function onKey(e: KeyboardEvent) {
14→  const next = e.shiftKey;
15→  if (next !== pressed) {
16→    pressed = next;
17→    for (const fn of listeners) fn(next);
18→  }
19→}
20→
21→function subscribe(fn: (v: boolean) => void) {
22→  listeners.add(fn);
23→  if (listeners.size === 1) {
24→    window.addEventListener("keydown", onKey);
25→    window.addEventListener("keyup", onKey);
26→  }
27→  return () => {
28→    listeners.delete(fn);
29→    if (listeners.size === 0) {
30→      window.removeEventListener("keydown", onKey);
31→      window.removeEventListener("keyup", onKey);
32→    }
33→  };
34→}
35→
36→export function useShiftKey(): boolean {
37→  const [shift, setShift] = useState(pressed);
38→  useEffect(() => subscribe(setShift), []);
39→  return shift;
40→}
